// ---------- 1. THE DATA ----------
// The player list now lives in players.json (generated by
// fetch-players.js) instead of being typed out here by hand.
// "players" starts empty and gets filled in once the file loads.
let players = [];

// ---------- 2. GAME STATE ----------
// Plain variables that live only while the page is open (no saving yet).
let currentPlayer = null;
let correctCount = 0;
let totalCount = 0;

// ---------- 3. PICK A RANDOM PLAYER AND SHOW THEIR STATS ----------
function newRound() {
  // Pick a random index from the players array
  const index = Math.floor(Math.random() * players.length);
  currentPlayer = players[index];

  // Build the stat lines as HTML (name is left out on purpose!)
  const statsDiv = document.getElementById("stats");
  statsDiv.innerHTML = `
    <div class="stat-line"><span class="stat-label">Team</span><span class="stat-value">${currentPlayer.team}</span></div>
    <div class="stat-line"><span class="stat-label">Season</span><span class="stat-value">${currentPlayer.year}</span></div>
    <div class="stat-line"><span class="stat-label">AVG</span><span class="stat-value">${currentPlayer.avg}</span></div>
    <div class="stat-line"><span class="stat-label">HR</span><span class="stat-value">${currentPlayer.hr}</span></div>
    <div class="stat-line"><span class="stat-label">RBI</span><span class="stat-value">${currentPlayer.rbi}</span></div>
  `;

  // Reset the input box and result message for the new round
  document.getElementById("guessInput").value = "";
  document.getElementById("result").innerHTML = "";
  document.getElementById("guessInput").focus();
}

// ---------- 4. CHECK THE GUESS ----------
function checkGuess() {
  const guess = document.getElementById("guessInput").value.trim().toLowerCase();
  const answer = currentPlayer.name.toLowerCase();
  const resultDiv = document.getElementById("result");

  totalCount++;

  if (guess === answer) {
    correctCount++;
    resultDiv.innerHTML = `<span class="correct">Correct! It was ${currentPlayer.name}.</span>`;
  } else {
    resultDiv.innerHTML = `<span class="wrong">Not quite. It was ${currentPlayer.name}.</span>`;
  }

  document.getElementById("score").textContent = `Score: ${correctCount} / ${totalCount}`;

  // Start the next round after a short pause so the player can read the answer
  setTimeout(newRound, 1500);
}

// ---------- 5. WIRE UP THE BUTTON AND ENTER KEY ----------
document.getElementById("submitBtn").addEventListener("click", checkGuess);
document.getElementById("guessInput").addEventListener("keydown", function(e) {
  if (e.key === "Enter") checkGuess();
});

// ---------- 6. LOAD THE DATA, THEN START THE FIRST ROUND ----------
// We can't call newRound() until players.json has actually loaded,
// so we wait for the fetch to finish first.
fetch("players.json")
  .then((res) => res.json())
  .then((data) => {
    players = data;
    newRound();
  })
  .catch((err) => {
    document.getElementById("stats").innerHTML =
      "Couldn't load players.json. Make sure you're running this through a local server, not by double-clicking index.html.";
    console.error(err);
  });